const langs = ["en", "ru", "es", "fr", "it", "uk", "de"];
for (const lang of langs) {
  const file = path.join(localesDir, `${lang}.json`);
  const current = JSON.parse(fs.readFileSync(file, "utf8"));
  for (const [key, translations] of Object.entries(ADDITIONS)) {
    if (translations[lang]) current[key] = translations[lang];
  }
  const sorted = Object.fromEntries(Object.keys(current).sort().map((k) => [k, current[k]]));
  fs.writeFileSync(file, `${JSON.stringify(sorted, null, 2)}\n`);
}
console.log(`Merged ${Object.keys(ADDITIONS).length} keys`);
